import json
import re

# Load data
with open(locals()['var_function-call-3354222467166054173'], 'r') as f:
    books_data = json.load(f)

with open(locals()['var_function-call-1866091341875104044'], 'r') as f:
    reviews_data = json.load(f)

# 1. Process reviews -> avg rating per book
book_ratings = {}
for r in reviews_data:
    pid = r['purchase_id']
    try:
        rating = float(r['rating'])
    except:
        continue

    match = re.search(r'purchaseid_(\d+)', pid)
    if match:
        id_num = int(match.group(1))
        if id_num not in book_ratings:
            book_ratings[id_num] = []
        book_ratings[id_num].append(rating)

book_avg_ratings = {}
for id_num, ratings in book_ratings.items():
    book_avg_ratings[id_num] = sum(ratings) / len(ratings)

# 2. Process books -> year
book_years = {}
year_pattern = re.compile(r'published.*?(\d{4})', re.IGNORECASE)

for b in books_data:
    bid = b['book_id']
    details = b['details']

    match = re.search(r'bookid_(\d+)', bid)
    if match:
        id_num = int(match.group(1))

        # Extract year
        match_year = year_pattern.search(details)
        if match_year:
            y = int(match_year.group(1))
            if 1800 <= y <= 2023:
                book_years[id_num] = y

# 3. Group by decade
decade_books = {} # decade -> list of avg_ratings

for id_num, avg_rating in book_avg_ratings.items():
    if id_num in book_years:
        year = book_years[id_num]
        decade = (year // 10) * 10
        decade_str = f"{decade}s"

        if decade_str not in decade_books:
            decade_books[decade_str] = []
        decade_books[decade_str].append(avg_rating)

# 4. Find best decade
best_decade = None
max_avg = -1

for decade, ratings in decade_books.items():
    count = len(ratings)
    if count >= 10:
        avg = sum(ratings) / count
        if avg > max_avg:
            max_avg = avg
            best_decade = decade

print("__RESULT__:")
print(json.dumps(best_decade))

